-- PostgreSQL panel-compatible import for image-idea
-- Generated by Codex on 2026-06-21 from local MySQL image-test database.
-- This fixed export normalizes stale foreign keys and casts JSON fields to jsonb.

SET client_encoding = 'UTF8';
SET standard_conforming_strings = on;
SET check_function_bodies = false;

DROP TABLE IF EXISTS "email_verification_codes" CASCADE;
DROP TABLE IF EXISTS "platform_settings" CASCADE;
DROP TABLE IF EXISTS "generation_jobs" CASCADE;
DROP TABLE IF EXISTS "payment_events" CASCADE;
DROP TABLE IF EXISTS "credit_ledger" CASCADE;
DROP TABLE IF EXISTS "user_plan_packages" CASCADE;
DROP TABLE IF EXISTS "orders" CASCADE;
DROP TABLE IF EXISTS "plans" CASCADE;
DROP TABLE IF EXISTS "balances" CASCADE;
DROP TABLE IF EXISTS "user_accounts" CASCADE;

CREATE TABLE "user_accounts" (
  "id" varchar(128) PRIMARY KEY,
  "username" varchar(191) UNIQUE,
  "email" varchar(191) UNIQUE,
  "password_hash" varchar(255),
  "display_name" varchar(191),
  "avatar_url" text,
  "phone" varchar(32),
  "admin_note" text,
  "role" varchar(32) NOT NULL DEFAULT 'user',
  "status" varchar(32) NOT NULL DEFAULT 'active',
  "last_login_at" timestamp,
  "created_at" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  "updated_at" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE "balances" (
  "user_id" varchar(128) PRIMARY KEY REFERENCES "user_accounts"("id") ON DELETE CASCADE,
  "available_credits" integer NOT NULL DEFAULT 0,
  "updated_at" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE "plans" (
  "id" varchar(128) PRIMARY KEY,
  "name" varchar(191) NOT NULL,
  "credits" integer NOT NULL,
  "price_cents" integer NOT NULL,
  "currency" varchar(8) NOT NULL DEFAULT 'CNY',
  "enabled" boolean NOT NULL DEFAULT true,
  "recommended" boolean NOT NULL DEFAULT false,
  "description" text,
  "created_at" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  "updated_at" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE "orders" (
  "id" varchar(128) PRIMARY KEY,
  "user_id" varchar(128) NOT NULL REFERENCES "user_accounts"("id") ON DELETE CASCADE,
  "plan_id" varchar(128) NOT NULL REFERENCES "plans"("id"),
  "status" varchar(32) NOT NULL DEFAULT 'pending',
  "original_amount_cents" integer NOT NULL DEFAULT 0,
  "amount_cents" integer NOT NULL,
  "balance_applied" integer NOT NULL DEFAULT 0,
  "balance_applied_cents" integer NOT NULL DEFAULT 0,
  "currency" varchar(8) NOT NULL DEFAULT 'CNY',
  "credits" integer NOT NULL,
  "provider" varchar(32) NOT NULL,
  "provider_order_id" varchar(191),
  "provider_payment_id" varchar(191),
  "created_at" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  "paid_at" timestamp
);
CREATE INDEX "orders_user_id_created_at_idx" ON "orders"("user_id", "created_at");

CREATE TABLE "user_plan_packages" (
  "id" varchar(128) PRIMARY KEY,
  "user_id" varchar(128) NOT NULL REFERENCES "user_accounts"("id") ON DELETE CASCADE,
  "plan_id" varchar(128) NOT NULL REFERENCES "plans"("id"),
  "order_id" varchar(128) NOT NULL UNIQUE,
  "total_uses" integer NOT NULL,
  "remaining_uses" integer NOT NULL,
  "status" varchar(32) NOT NULL DEFAULT 'active',
  "expires_at" timestamp,
  "created_at" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  "updated_at" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP
);
CREATE INDEX "user_plan_packages_user_id_status_created_at_idx" ON "user_plan_packages"("user_id", "status", "created_at");

CREATE TABLE "credit_ledger" (
  "id" varchar(128) PRIMARY KEY,
  "user_id" varchar(128) NOT NULL REFERENCES "user_accounts"("id") ON DELETE CASCADE,
  "type" varchar(32) NOT NULL,
  "amount" integer NOT NULL,
  "balance_after" integer NOT NULL,
  "source" varchar(32) NOT NULL,
  "source_id" varchar(191) UNIQUE,
  "description" text,
  "created_at" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP
);
CREATE INDEX "credit_ledger_user_id_created_at_idx" ON "credit_ledger"("user_id", "created_at");

CREATE TABLE "payment_events" (
  "id" varchar(128) PRIMARY KEY,
  "provider" varchar(32) NOT NULL,
  "provider_event_id" varchar(128) NOT NULL,
  "order_id" varchar(128),
  "processed_at" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  "raw" jsonb NOT NULL
);
CREATE UNIQUE INDEX "payment_events_provider_provider_event_id_key" ON "payment_events"("provider", "provider_event_id");

CREATE TABLE "generation_jobs" (
  "id" varchar(128) PRIMARY KEY,
  "user_id" varchar(128) NOT NULL REFERENCES "user_accounts"("id") ON DELETE CASCADE,
  "status" varchar(32) NOT NULL DEFAULT 'queued',
  "prompt" text NOT NULL,
  "request_params" jsonb NOT NULL,
  "input_image_data" jsonb NOT NULL DEFAULT '[]'::jsonb,
  "mask_data_url" text,
  "cost_credits" integer NOT NULL,
  "images" jsonb NOT NULL DEFAULT '[]'::jsonb,
  "raw_image_urls" jsonb,
  "revised_prompts" jsonb,
  "actual_params" jsonb,
  "error_message" text,
  "created_at" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  "started_at" timestamp,
  "finished_at" timestamp
);
CREATE INDEX "generation_jobs_user_id_created_at_idx" ON "generation_jobs"("user_id", "created_at");
CREATE INDEX "generation_jobs_status_created_at_idx" ON "generation_jobs"("status", "created_at");

CREATE TABLE "platform_settings" (
  "setting_key" varchar(191) PRIMARY KEY,
  "setting_value" text,
  "updated_at" timestamp NOT NULL
);

CREATE TABLE "email_verification_codes" (
  "id" varchar(64) PRIMARY KEY,
  "email" varchar(191) NOT NULL,
  "purpose" varchar(32) NOT NULL,
  "code" varchar(12) NOT NULL,
  "expires_at" timestamp NOT NULL,
  "used_at" timestamp,
  "created_at" timestamp NOT NULL
);
CREATE INDEX "email_verification_lookup" ON "email_verification_codes"("email", "purpose", "code");

